HRESULT MRFNSD::UpdateFeature()
{
	CATFmFeatureFacade FeatFacadeOnTWI(_CredentialForTWI, this);
	HRESULT rc = FeatFacadeOnTWI.IsUpToDate();
	if (S_FALSE == rc)
	{
		rc = FeatFacadeOnTWI.Update();
		if (SUCCEEDED(rc))
		{
			CATBaseUnknown *pNSDObject = NULL;
			rc = FeatFacadeOnTWI.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)&pNSDObject);
			if (SUCCEEDED(rc) && NULL != pNSDObject)
			{
				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(pNSDObject, 0, 0);

				pNSDObject->Release();
				pNSDObject = NULL;
			}
		}
	}

	return rc;
} 

